for (const operation of ZOOM_CONTACT_CENTER_FULL_API_OPERATIONS) {
  if (!ZOOM_CONTACT_CENTER_FULL_API_OPERATION_BY_ID.has(operation.operationId)) {
    ZOOM_CONTACT_CENTER_FULL_API_OPERATION_BY_ID.set(operation.operationId, operation);
  }
}

